        await SettingsService.SaveProfileAsync(profile);
        savedProfile = profile;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        if (savedProfile != null)
        {
            editProfile = EditableProfile.FromModel(savedProfile);
        }
        ShowToast("Changes discarded.", "info");
    }

    // Notifications methods
    private void ToggleChannelMute(string channel, bool muted)
    {
        if (muted && !editNotifications.MutedChannels.Contains(channel))
        {
            editNotifications.MutedChannels.Add(channel);
        }
        else if (!muted)
        {
            editNotifications.MutedChannels.Remove(channel);
        }
    }

    private async Task SaveNotifications()
    {
        var prefs = editNotifications.ToModel();
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        ShowToast("Notification preferences saved!", "success");
    }

    // Security methods
    private async Task ChangePassword()
    {
        passwordError = string.Empty;

        if (string.IsNullOrWhiteSpace(currentPassword))
        {
            passwordError = "Current password is required.";
            return;
        }

        if (string.IsNullOrWhiteSpace(newPassword))
        {
            passwordError = "New password is required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            passwordError = "New password must be at least 8 characters.";
            return;
        }

        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            currentPassword = string.Empty;
            newPassword = string.Empty;
            confirmPassword = string.Empty;
            showChangePassword = false;
            ShowToast("Password updated successfully!", "success");
            securitySettings = await SettingsService.GetSecuritySettingsAsync();
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
    }

    private void ConfirmRevokeSession(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeConfirmation = true;
    }

    private async Task RevokeSession()
    {
        if (sessionToRevoke != null)
        {
            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
            securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked.", "success");
        }
        showRevokeConfirmation = false;
        sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        showRevokeConfirmation = false;
        sessionToRevoke = null;
    }

    // Appearance methods
    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{editAppearance.Theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{editAppearance.FontSize.ToLowerInvariant()}");
        if (editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        var settings = editAppearance.ToModel();
        await SettingsService.SaveAppearanceAsync(settings);
        ShowToast("Appearance settings saved!", "success");
    }

    // Toast helper
    private void ShowToast(string message, string type)
    {
        toastMessage = message;
        toastType = type;
        _ = DismissToastAfterDelay();
    }

    private async Task DismissToastAfterDelay()
    {
        await Task.Delay(3000);
        toastMessage = string.Empty;
        await InvokeAsync(StateHasChanged);
    }

    // Editable view models
    private class EditableProfile
    {
        public string DisplayName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string AvatarUrl { get; set; } = string.Empty;
        public string Bio { get; set; } = string.Empty;

        public static EditableProfile FromModel(UserProfile model) => new()
        {
            DisplayName = model.DisplayName,
            Email = model.Email,
            AvatarUrl = model.AvatarUrl,
            Bio = model.Bio
        };

        public UserProfile ToModel() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private class EditableNotifications
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = new();

        public static EditableNotifications FromModel(NotificationPrefs model) => new()
        {
            EmailNotifications = model.EmailNotifications,
            PushNotifications = model.PushNotifications,
            WeeklyDigest = model.WeeklyDigest,
            MutedChannels = new List<string>(model.MutedChannels)
        };

        public NotificationPrefs ToModel() => new(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
    }

    private class EditableAppearance
    {
        public string Theme { get; set; } = "System";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "en";
        public bool CompactMode { get; set; }

        public static EditableAppearance FromModel(AppearanceSettings model) => new()
        {
            Theme = model.Theme,
            FontSize = model.FontSize,
            Language = model.Language,
            CompactMode = model.CompactMode
        };

        public AppearanceSettings ToModel() => new(Theme, FontSize, Language, CompactMode);
    }
}

