arguments.file_text:
.settings-container {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar Navigation */
.settings-sidebar {
    width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    flex-shrink: 0;
}

.settings-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-sidebar li {
    padding: 0.75rem 1.5rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    color: #495057;
    font-weight: 500;
    transition: all 0.2s ease;
    border-left: 3px solid transparent;
}

.settings-sidebar li:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.1rem;
}

/* Main Content */
.settings-content {
    flex: 1;
    padding: 2rem 3rem;
    max-width: 800px;
    position: relative;
}

.settings-section h2 {
    margin-bottom: 1.5rem;
    color: #212529;
    font-size: 1.5rem;
    border-bottom: 1px solid #dee2e6;
    padding-bottom: 0.75rem;
}

.settings-section h3 {
    margin-top: 1.5rem;
    margin-bottom: 1rem;
    color: #495057;
    font-size: 1.1rem;
}

/* Loading */
.loading-spinner {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 200px;
    color: #6c757d;
    font-size: 1.1rem;
}

/* Form Elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    color: #495057;
    font-size: 0.9rem;
}

.form-group input[type="text"],
.form-group input[type="email"],
